insert tb_cs_meeting (
	subject
	, lang
	, time_duration_ms
	, file_org_nm
	, file_new_nm
	, file_conv_nm
	, file_size_bytes
	, tc_user_seq
	, error_message
	, upload_type
) value (
	#{subject}
	, #{lang}
	, #{timeDurationStr}
	, #{orgnm}
	, #{newnm}
	, #{convnm}
	, #{fileSizeBytes}
	, #{tcUserSeq}
	, #{errorMessage}
	, #{type}
)

insert tb_cs_meeting_api (
	  subject
	, time_duration_ms
	, file_org_nm
	, file_new_nm
	, file_conv_nm
	, file_size_bytes
	, tc_user_seq
	, status
) value (
	  #{subject}
	, #{timeDurationStr}
	, #{orgnm}
	, #{newnm}
	, #{convnm}
	, #{fileSizeBytes}
	, #{tcUserSeq}
	, '10'
)

