update tb_cs_meeting_api set
	  time_duration_ms = #{timeDurationMs}
	, meeting_seq = #{meetingSeq}
	, status = #{status}

		, stt_started_at = #{sttStartedAt}


		, stt_duration = #{sttDuration}

where seq = #{seq}

update tb_cs_meeting_api set
	status = #{status}
where seq = #{seq}

update tb_cs_meeting_api_test set
	  time_duration_ms = #{timeDurationMs}
	, meeting_seq = #{meetingSeq}
	, status = #{status}
where seq = #{seq}

mapper.select:
select seq as seq , subject , time_duration_ms as timeDurationMs , file_org_nm as fileOrgNm , file_new_nm as fileNewNm , file_size_bytes as fileSizeBytes , tc_user_seq as tcUserSeq , status as status , meeting_seq as meetingSeq from tb_cs_meeting_api where 1 = 1
and status = #{status}
and seq = #{seq}
order by seq

select api.seq as seq , api.meeting_seq , api.status , api.subject , DATE_FORMAT(api.created_at, '%Y-%m-%d %H:%i') as created_at , DATE_FORMAT(tt.trashed_at, '%Y-%m-%d %H:%i') as trashed_at , DATE_FORMAT(tt.deleted_at, '%Y-%m-%d %H:%i') as deleted_at , api.time_duration_ms , api.file_org_nm , api.file_new_nm , api.file_conv_nm , api.file_size_bytes , ( SELECT COUNT(*) from tb_cs_meeting_api apia LEFT JOIN tb_cs_meeting tta ON tta.seq = apia.meeting_seq LEFT JOIN tb_cs_info_user iua ON iua.seq = apia.tc_user_seq WHERE 1 = 1
AND iua.tc_id = #{user.tcId}
AND apia.subject LIKE concat('%', #{search.searchText}, '%') OR apia.file_org_nm LIKE concat('%', #{search.searchText}, '%')
) as hiddenCount , iu.tc_name , iu.tc_id , iu.tv_level from tb_cs_meeting_api api LEFT JOIN tb_cs_meeting tt ON tt.seq = api.meeting_seq LEFT JOIN tb_cs_info_user iu ON iu.seq = api.tc_user_seq WHERE 1 = 1
AND iu.tc_id = #{user.tcId}
AND api.subject LIKE concat('%', #{search.searchText}, '%') OR api.file_org_nm LIKE concat('%', #{search.searchText}, '%')
order by api.created_at desc
limit #{offsetPageable.offset}, #{offsetPageable.pageSize}

select seq as seq , subject , time_duration_ms as timeDurationMs , file_org_nm as fileOrgNm , file_new_nm as fileNewNm , file_conv_nm as fileConvNm , file_size_bytes as fileSizeBytes , tc_user_seq as tcUserSeq , status as status , meeting_seq as meetingSeq from tb_cs_meeting_api where 1 = 1
and status = #{status}
and seq > #{seq}
order by seq

select seq as seq , subject , time_duration_ms as timeDurationMs , file_org_nm as fileOrgNm , file_new_nm as fileNewNm , file_size_bytes as fileSizeBytes , tc_user_seq as tcUserSeq , status as status , meeting_seq as meetingSeq from tb_cs_meeting_api_test where 1 = 1
and status = #{status}
and seq > #{seq}
order by seq

